return $input.all().map((item) => {
  const comments = item.json.comments || [];

  // 1. Limpiamos el texto uniendo los cuerpos de los comentarios
  const textoLimpio = comments.map(c => c.body).join('\n---\n');

  // 2. Buscamos el ID del ticket usando pairedItem
  let ticketId = "Sin ID";
  try {
    ticketId = $("Get many tickets").item(item.pairedItem.item).json.id;
  } catch (e) {
    ticketId = "Error al recuperar ID";
  }

  return {
    json: {
      ticket_id: ticketId,
      resumen_input: textoLimpio
    },
    pairedItem: item.pairedItem 
  };
});

// 1. Recogemos los tickets procesados
const entradas = $input.all();
const totalTickets = entradas.length;

// 2. Datos de la organización (obtenidos del primer nodo de referencia)
const orgData = $("Get an organization").first().json;
const nombreOrg = orgData.name || "Cliente Desconocido";
const orgId = orgData.id || "ID Desconocido";

// 3. Formateo del listado de tickets para la IA
const listadoTickets = entradas.map((item, index) => {
  return `--- TICKET ${index + 1} (ID: ${item.json.ticket_id}) ---
HISTORIAL Y RESUMEN:
${item.json.resumen_input}
`;
}).join('\n');

// 4. Construcción del Super Prompt
const superPrompt = `
### ROL
Actúa como un Senior Technical Project Manager. Tu objetivo es sintetizar la actividad de soporte para facilitar la toma de decisiones estratégicas.

### CONTEXTO
- **CLIENTE**: ${nombreOrg.toUpperCase()}
- **ID ORGANIZACIÓN**: ${orgId}
- **VOLUMEN**: ${totalTickets} tickets analizados en este periodo.

### DATOS DE ENTRADA
${listadoTickets}

### ESTRUCTURA DEL INFORME REQUERIDA
Por favor, genera un informe profesional en Markdown siguiendo este esquema:

1. **RESUMEN EJECUTIVO**: Diagnóstico general de la situación del cliente (salud de la cuenta).
2. **ANÁLISIS POR TICKET**: Breve síntesis (máximo 2 líneas) por cada caso, resaltando el problema técnico.
3. **PATRONES Y CORRELACIONES**: Identificación de errores recurrentes, bugs de producto o fricciones en la UX.
4. **HOJA DE RUTA (PLAN DE ACCIÓN)**:
    - 🛠️ **Soporte**: Próximos pasos para cerrar los casos abiertos.
    - 💻 **Desarrollo**: Sugerencias de mejora técnica o correcciones necesarias.
5. **MÉTRICA DE RIESGO (CHURN)**: Escala 1-10 y justificación cualitativa.

### FORMATO Y TONO
- Profesional, directo y orientado a la solución.
- Usa emojis (🚨, ✅, 🛠️, 📈) para facilitar la lectura rápida.
`;

// --- SOLUCIÓN PARA LAS COMILLAS (PARCHE FINAL) ---
// Convertimos a string seguro para JSON y quitamos las comillas externas
const promptSeguro = JSON.stringify(superPrompt).slice(1, -1);

// 5. Salida del nodo
return {
  json: {
    prompt_final: promptSeguro,
    cliente: nombreOrg,
    id_organizacion: orgId,
    fecha_proceso: new Date().toISOString().split('T')[0]
  }
};

