return $input.all().map(item => {
  // 1. Acceder al texto dentro de la estructura del mensaje
  const texto = item.json.output[0].content[0].text;

  // 2. Buscamos patrones comunes como "Escala", "Riesgo", "Nivel" o "Métrica"
  // Seguida de dos puntos, espacios opcionales y un número.
  // La "i" al final hace que no importe si es mayúscula o minúscula.
  const regex = /(?:Escala|Riesgo|Nivel|Métrica|Valoración):\s*(\d+)/i;

  const match = texto.match(regex);

  // 3. Si no encuentra el patrón anterior, buscamos cualquier número que esté 
  // cerca de la palabra "Churn" al final del documento.
  let valorFinal = null;

  if (match) {
    valorFinal = parseInt(match[1], 10);
  } else {
    // Intento de rescate: buscar el último número (\d+) que aparezca después de la palabra "Churn"
    const rescueMatch = texto.match(/churn.*?\s(\d+)/is);
    valorFinal = rescueMatch ? parseInt(rescueMatch[1], 10) : null;
  }

  // 4. Limitar el resultado entre 1 y 10 por seguridad
  if (valorFinal !== null) {
    valorFinal = Math.max(1, Math.min(10, valorFinal));
  }

  return {
    json: {
      churn_score: valorFinal,
      organizacion: item.json.output[0].id // Opcional: mantener una referencia
    }
  };
});

